from braket.circuits import Circuit

def make_oracle(circuit, f, n, input_qubits, ancilla):
    """
    Dynamically builds a Deutsch-Jozsa oracle from a classical boolean function f(x).
    Note: Currently supports up to n=2 due to native gate constraints.
    """
    for i in range(2**n):
        if f(i) == 1:
            # 1. Flip 0-bits to activate multi-controlled-X
            for j in range(n):
                if not (i >> (n - 1 - j)) & 1:
                    circuit.x(input_qubits[j])

            # 2. Multi-controlled X on ancilla
            if n == 1:
                circuit.cnot(input_qubits[0], ancilla)
            elif n == 2:
                circuit.ccnot(input_qubits[0], input_qubits[1], ancilla)
            else:
                # For n > 2, decompose into Toffoli chain using auxiliary qubits
                raise NotImplementedError("Dynamic Toffoli chains for n > 2 are not yet implemented.")

            # 3. Undo the flips (uncompute)
            for j in range(n):
                if not (i >> (n - 1 - j)) & 1:
                    circuit.x(input_qubits[j])

    return circuit

