def qaoa_layer(qubits, graph, gamma, beta):
    circuit = Circuit()

    for u, v in graph.edges:
        circuit.zz(qubits[u], qubits[v], 2 * gamma)

    for q in qubits:
        circuit.rx(q, 2 * beta)

    return circuit

