def qft_3(qubits, reverse=True):
    circuit = Circuit()
    n = 3
    for i in range(n):
        circuit.h(qubits[i])
        for j in range(i + 1, n):
            angle = np.pi / (2 ** (j - i))
            circuit.cphaseshift(qubits[j], qubits[i], angle)
    if reverse:
        circuit.swap(qubits[0], qubits[2])
    return circuit

