import sympy

def find_factor(n, order_finder, max_attempts=30):
    """
    Executes the classical post-processing of Shor's algorithm to find a non-trivial factor of n.
    """
    # 1. Base cases: Prime or Even
    if sympy.isprime(n):
        return None
    if n % 2 == 0:
        return 2

    # 2. Check if n is a prime power (a^b)
    for k in range(2, math.floor(math.log2(n)) + 1):
        c = math.pow(n, 1 / k)
        if math.floor(c) ** k == n:
            return math.floor(c)
        if math.ceil(c) ** k == n:
            return math.ceil(c)

    # 3. Randomized search for factors using the order finder
    for _ in range(max_attempts):
        x = random.randint(2, n - 1)

        # Check if we got lucky and guessed a factor
        c = math.gcd(x, n)
        if 1 < c < n:
            return c

        # Call the quantum subroutine to find the period 'r'
        r = order_finder(x, n)
        if r is None or r % 2 != 0:
            continue

        # 4. Modular exponentiation (avoiding memory overflow)
        y = pow(x, r // 2, n)

        # If y == -1 mod n, it's a trivial factor, try a new x
        if y == n - 1:
            continue

        # 5. Extract factors using the Greatest Common Divisor
        c1 = math.gcd(y - 1, n)
        if 1 < c1 < n:
            return c1

        c2 = math.gcd(y + 1, n)
        if 1 < c2 < n:
            return c2

    return None

from braket.circuits import Circuit

def stabilizer_encode(circuit, additional_qubits, unencoded_qubits, logical_Xs, M, r, n, k):
    """
    Encodes logical qubits into physical qubits based on the stabilizer matrix M.
    """
    # Map stabilizer string operators directly to Braket's controlled gate methods
    controlled_gate_map = {'X': 'cnot', 'Y': 'cy', 'Z': 'cz'}
    qubits = additional_qubits + unencoded_qubits

    # 1. Map logical X operations to the physical register
    # FIXED: Iterate over the n-k ancilla qubits (0 to n-k) to apply the CNOTs
    for idx, x in enumerate(logical_Xs):
        for j in range(n - k):
            if x[j] in ['X', 'Y']:
                circuit.cnot(unencoded_qubits[idx], additional_qubits[j])

    # 2. Entangle physical qubits based on the Stabilizer Matrix M
    for row in range(r):
        circuit.h(qubits[row])

        # Apply S gate for Y and Z stabilizers to correct the phase
        if M[row][row] in ['Y', 'Z']:
            circuit.s(qubits[row])

        for col in range(n):
            if col == row or M[row][col] == 'I':
                continue

            # Dynamically apply the correct controlled gate (cnot, cy, or cz)
            c_op = controlled_gate_map[M[row][col]]
            getattr(circuit, c_op)(qubits[row], qubits[col])

    return circuit
